/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications.
 * Currently supports email as the only channel, with per-category
 * opt-in/out and frequency settings.
 */

import type { NotificationType } from './notification.js';

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  /** Master switch — when false, no emails are sent regardless of other settings. */
  enabled: boolean;
  /** How often email notifications are delivered. */
  frequency: 'immediate' | 'daily-digest' | 'weekly-digest';
  /** Per-category subscription toggles. */
  categories: {
    orderConfirmations: boolean;
    orderStatusUpdates: boolean;
    welcomeMessages: boolean;
    profileUpdates: boolean;
  };
}

/**
 * Full user preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailNotificationPreferences['frequency'];
  categories?: Partial<EmailNotificationPreferences['categories']>;
}

/**
 * Default email preferences for new users — all notifications enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: {
    orderConfirmations: true,
    orderStatusUpdates: true,
    welcomeMessages: true,
    profileUpdates: true,
  },
};

/**
 * Maps NotificationType to the corresponding category key in EmailNotificationPreferences.
 */
export const NOTIFICATION_TYPE_TO_CATEGORY: Record<
  NotificationType,
  keyof EmailNotificationPreferences['categories']
> = {
  'order:confirmation': 'orderConfirmations',
  'order:status-update': 'orderStatusUpdates',
  'user:welcome': 'welcomeMessages',
  'user:profile-updated': 'profileUpdates',
};

parameters.new_string:
/**
 * User notification preferences model.
 *
 * Controls how and when a user receives notifications across multiple channels.
 * Supports email, SMS, and webhook channels with per-category opt-in/out settings.
 *
 * DECISION CHANGE (Session 9): The original model (Session 3) assumed email-only.
 * Session 8 added SMS support and flagged that preferences needed updating.
 * This refactor adds per-channel preference settings for email, SMS, and webhook.
 * Existing email preferences are preserved for backward compatibility.
 */

import type { NotificationType } from './notification.js';

/**
 * Per-category subscription toggles, shared across all channels.
 */
export interface NotificationCategories {
  orderConfirmations: boolean;
  orderStatusUpdates: boolean;
  welcomeMessages: boolean;
  profileUpdates: boolean;
}

/**
 * Email-specific notification preferences.
 */
export interface EmailNotificationPreferences {
  /** Master switch — when false, no emails are sent regardless of other settings. */
  enabled: boolean;
  /** How often email notifications are delivered. */
  frequency: 'immediate' | 'daily-digest' | 'weekly-digest';
  /** Per-category subscription toggles. */
  categories: NotificationCategories;
}

/**
 * SMS-specific notification preferences.
 */
export interface SmsNotificationPreferences {
  /** Master switch — when false, no SMS are sent regardless of other settings. */
  enabled: boolean;
  /** Phone number for SMS delivery. */
  phoneNumber?: string;
  /** Per-category subscription toggles. */
  categories: NotificationCategories;
}

/**
 * Webhook-specific notification preferences.
 */
export interface WebhookNotificationPreferences {
  /** Master switch — when false, no webhooks are sent regardless of other settings. */
  enabled: boolean;
  /** Webhook endpoint URL. */
  url?: string;
  /** Per-category subscription toggles. */
  categories: NotificationCategories;
}

/**
 * Full user preferences record.
 */
export interface UserPreferences {
  id: string;
  userId: string;
  email: EmailNotificationPreferences;
  sms: SmsNotificationPreferences;
  webhook: WebhookNotificationPreferences;
  createdAt: Date;
  updatedAt: Date;
}

/**
 * Input for updating email notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateEmailPreferencesInput {
  enabled?: boolean;
  frequency?: EmailNotificationPreferences['frequency'];
  categories?: Partial<NotificationCategories>;
}

/**
 * Input for updating SMS notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateSmsPreferencesInput {
  enabled?: boolean;
  phoneNumber?: string;
  categories?: Partial<NotificationCategories>;
}

/**
 * Input for updating webhook notification preferences.
 * All fields are optional — only provided fields are changed.
 */
export interface UpdateWebhookPreferencesInput {
  enabled?: boolean;
  url?: string;
  categories?: Partial<NotificationCategories>;
}

/**
 * Default category settings — all enabled.
 */
export const DEFAULT_CATEGORIES: NotificationCategories = {
  orderConfirmations: true,
  orderStatusUpdates: true,
  welcomeMessages: true,
  profileUpdates: true,
};

/**
 * Default email preferences for new users — all notifications enabled, immediate delivery.
 */
export const DEFAULT_EMAIL_PREFERENCES: EmailNotificationPreferences = {
  enabled: true,
  frequency: 'immediate',
  categories: { ...DEFAULT_CATEGORIES },
};

/**
 * Default SMS preferences for new users — disabled by default (opt-in).
 */
export const DEFAULT_SMS_PREFERENCES: SmsNotificationPreferences = {
  enabled: false,
  categories: { ...DEFAULT_CATEGORIES },
};

/**
 * Default webhook preferences for new users — disabled by default (opt-in).
 */
export const DEFAULT_WEBHOOK_PREFERENCES: WebhookNotificationPreferences = {
  enabled: false,
  categories: { ...DEFAULT_CATEGORIES },
};

/**
 * Maps NotificationType to the corresponding category key.
 */
export const NOTIFICATION_TYPE_TO_CATEGORY: Record<
  NotificationType,
  keyof NotificationCategories
> = {
  'order:confirmation': 'orderConfirmations',
  'order:status-update': 'orderStatusUpdates',
  'user:welcome': 'welcomeMessages',
  'user:profile-updated': 'profileUpdates',
};

