/**
 * Pure validation functions for notification preferences.
 *
 * These functions contain no side effects and no database calls.
 * They accept pre-fetched data and validate business rules.
 *
 * Supports per-channel preference checks for email, SMS, and webhook.
 */

import type { UserPreferences } from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import { NOTIFICATION_TYPE_TO_CATEGORY } from '../models/user-preferences.js';

/**
 * Determine whether an email notification should be sent based on user preferences.
 *
 * Returns true if:
 * - Preferences are undefined (defaults allow all email notifications)
 * - Email is enabled AND the category for the notification type is enabled
 */
export function shouldSendEmailForPreferences(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
): boolean {
  if (!preferences) {
    return true;
  }
  if (!preferences.email.enabled) {
    return false;
  }
  const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
  return preferences.email.categories[categoryKey];
}

/**
 * Determine whether an SMS notification should be sent based on user preferences.
 *
 * Returns true if:
 * - Preferences are undefined (defaults: SMS disabled, so returns false)
 * - SMS is enabled AND the category for the notification type is enabled
 *
 * Note: Unlike email, SMS defaults to disabled for new users (opt-in model).
 */
export function shouldSendSmsForPreferences(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences set — SMS defaults to disabled
  if (!preferences) {
    return false;
  }
  if (!preferences.sms.enabled) {
    return false;
  }
  const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
  return preferences.sms.categories[categoryKey];
}

/**
 * Determine whether a webhook notification should be sent based on user preferences.
 *
 * Returns true if:
 * - Webhook is enabled AND the category for the notification type is enabled
 *
 * Note: Webhook defaults to disabled for new users (opt-in model).
 */
export function shouldSendWebhookForPreferences(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
): boolean {
  // No preferences set — webhook defaults to disabled
  if (!preferences) {
    return false;
  }
  if (!preferences.webhook.enabled) {
    return false;
  }
  const categoryKey = NOTIFICATION_TYPE_TO_CATEGORY[notificationType];
  return preferences.webhook.categories[categoryKey];
}

/**
 * Check whether a notification should be sent on the given channel
 * based on user preferences. Dispatches to the channel-specific function.
 */
export function shouldSendForChannel(
  preferences: UserPreferences | undefined,
  notificationType: NotificationType,
  channel: NotificationChannel,
): boolean {
  switch (channel) {
    case 'email':
      return shouldSendEmailForPreferences(preferences, notificationType);
    case 'sms':
      return shouldSendSmsForPreferences(preferences, notificationType);
    case 'webhook':
      return shouldSendWebhookForPreferences(preferences, notificationType);
    case 'in-app':
      // In-app notifications are always delivered (no preference control yet)
      return true;
  }
}

/**
 * Preferences service — manages user notification preferences.
 *
 * Provides CRUD operations for user preferences and exposes methods
 * to check whether a notification should be sent for a given user,
 * notification type, and channel.
 *
 * Supports per-channel preferences for email, SMS, and webhook.
 *
 * Depends on:
 * - PreferencesRepository for data access
 * - UserRepository to verify user existence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  UserPreferences,
  UpdateEmailPreferencesInput,
  UpdateSmsPreferencesInput,
  UpdateWebhookPreferencesInput,
} from '../models/user-preferences.js';
import type { NotificationType, NotificationChannel } from '../models/notification.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import {
  shouldSendEmailForPreferences,
  shouldSendSmsForPreferences,
  shouldSendWebhookForPreferences,
  shouldSendForChannel,
} from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns undefined if the user has no preferences set.
   */
  getPreferences(userId: string): UserPreferences | undefined {
    return this.preferencesRepository.findByUserId(userId);
  }

  /**
   * Get preferences for a user, creating default preferences if none exist.
   * Throws if the user does not exist.
   */
  getOrCreatePreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    const user = this.userRepository.findById(userId);
    if (!user) {
      throw new Error(`User not found: ${userId}`);
    }

    this.logger.info(`Creating default preferences for user ${userId}`);
    const now = new Date();
    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId,
      email: { ...DEFAULT_EMAIL_PREFERENCES, categories: { ...DEFAULT_EMAIL_PREFERENCES.categories } },
      sms: { ...DEFAULT_SMS_PREFERENCES, categories: { ...DEFAULT_SMS_PREFERENCES.categories } },
      webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, categories: { ...DEFAULT_WEBHOOK_PREFERENCES.categories } },
      createdAt: now,
      updatedAt: now,
    };

    return this.preferencesRepository.save(preferences);
  }

  /**
   * Update email notification preferences for a user.
   * Creates default preferences first if none exist.
   * Throws if the user does not exist.
   */
  updateEmailPreferences(
    userId: string,
    input: UpdateEmailPreferencesInput,
  ): UserPreferences {
    const preferences = this.getOrCreatePreferences(userId);

    const updatedEmail = { ...preferences.email };

    if (input.enabled !== undefined) {
      updatedEmail.enabled = input.enabled;
    }
    if (input.frequency !== undefined) {
      updatedEmail.frequency = input.frequency;
    }
    if (input.categories) {
      updatedEmail.categories = {
        ...updatedEmail.categories,
        ...input.categories,
      };
    }

    this.logger.info(`Updating email preferences for user ${userId}`);
    return this.preferencesRepository.update(preferences.id, {
      email: updatedEmail,
      updatedAt: new Date(),
    });
  }

  /**
   * Update SMS notification preferences for a user.
   * Creates default preferences first if none exist.
   * Throws if the user does not exist.
   */
  updateSmsPreferences(
    userId: string,
    input: UpdateSmsPreferencesInput,
  ): UserPreferences {
    const preferences = this.getOrCreatePreferences(userId);

    const updatedSms = { ...preferences.sms };

    if (input.enabled !== undefined) {
      updatedSms.enabled = input.enabled;
    }
    if (input.phoneNumber !== undefined) {
      updatedSms.phoneNumber = input.phoneNumber;
    }
    if (input.categories) {
      updatedSms.categories = {
        ...updatedSms.categories,
        ...input.categories,
      };
    }

    this.logger.info(`Updating SMS preferences for user ${userId}`);
    return this.preferencesRepository.update(preferences.id, {
      sms: updatedSms,
      updatedAt: new Date(),
    });
  }

  /**
   * Update webhook notification preferences for a user.
   * Creates default preferences first if none exist.
   * Throws if the user does not exist.
   */
  updateWebhookPreferences(
    userId: string,
    input: UpdateWebhookPreferencesInput,
  ): UserPreferences {
    const preferences = this.getOrCreatePreferences(userId);

    const updatedWebhook = { ...preferences.webhook };

    if (input.enabled !== undefined) {
      updatedWebhook.enabled = input.enabled;
    }
    if (input.url !== undefined) {
      updatedWebhook.url = input.url;
    }
    if (input.categories) {
      updatedWebhook.categories = {
        ...updatedWebhook.categories,
        ...input.categories,
      };
    }

    this.logger.info(`Updating webhook preferences for user ${userId}`);
    return this.preferencesRepository.update(preferences.id, {
      webhook: updatedWebhook,
      updatedAt: new Date(),
    });
  }

  /**
   * Check whether a notification of the given type should be sent to the user
   * via the email channel.
   */
  shouldSendEmail(userId: string, notificationType: NotificationType): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    return shouldSendEmailForPreferences(preferences, notificationType);
  }

  /**
   * Check whether a notification of the given type should be sent to the user
   * via the SMS channel.
   */
  shouldSendSms(userId: string, notificationType: NotificationType): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    return shouldSendSmsForPreferences(preferences, notificationType);
  }

  /**
   * Check whether a notification of the given type should be sent to the user
   * via the webhook channel.
   */
  shouldSendWebhook(userId: string, notificationType: NotificationType): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    return shouldSendWebhookForPreferences(preferences, notificationType);
  }

  /**
   * Check whether a notification should be sent on the given channel.
   * Generic method that dispatches to the channel-specific check.
   */
  shouldSendOnChannel(userId: string, notificationType: NotificationType, channel: NotificationChannel): boolean {
    const preferences = this.preferencesRepository.findByUserId(userId);
    return shouldSendForChannel(preferences, notificationType, channel);
  }
}

