import { describe, it, expect } from 'vitest';
import {
  shouldSendEmailForPreferences,
  shouldSendSmsForPreferences,
  shouldSendWebhookForPreferences,
  shouldSendForChannel,
} from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';
import {
  DEFAULT_EMAIL_PREFERENCES,
  DEFAULT_SMS_PREFERENCES,
  DEFAULT_WEBHOOK_PREFERENCES,
} from '../../src/models/user-preferences.js';

const makePreferences = (
  overrides: Partial<UserPreferences> = {},
): UserPreferences => ({
  id: 'pref-0001',
  userId: 'user-0001',
  email: { ...DEFAULT_EMAIL_PREFERENCES, categories: { ...DEFAULT_EMAIL_PREFERENCES.categories } },
  sms: { ...DEFAULT_SMS_PREFERENCES, categories: { ...DEFAULT_SMS_PREFERENCES.categories } },
  webhook: { ...DEFAULT_WEBHOOK_PREFERENCES, categories: { ...DEFAULT_WEBHOOK_PREFERENCES.categories } },
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('preferences.validator', () => {
  describe('shouldSendEmailForPreferences', () => {
    it('should return true when preferences are undefined', () => {
      expect(shouldSendEmailForPreferences(undefined, 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is enabled', () => {
      const prefs = makePreferences();
      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: { ...DEFAULT_EMAIL_PREFERENCES.categories },
          enabled: false,
        },
      });
      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should return false when specific category is disabled', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: {
            ...DEFAULT_EMAIL_PREFERENCES.categories,
            orderConfirmations: false,
          },
        },
      });
      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should return true for enabled category even if another is disabled', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: {
            ...DEFAULT_EMAIL_PREFERENCES.categories,
            orderConfirmations: false,
          },
        },
      });
      expect(shouldSendEmailForPreferences(prefs, 'order:status-update')).toBe(true);
    });

    it('should check each notification type against its category', () => {
      const prefs = makePreferences({
        email: {
          ...DEFAULT_EMAIL_PREFERENCES,
          categories: {
            orderConfirmations: true,
            orderStatusUpdates: false,
            welcomeMessages: true,
            profileUpdates: false,
          },
        },
      });

      expect(shouldSendEmailForPreferences(prefs, 'order:confirmation')).toBe(true);
      expect(shouldSendEmailForPreferences(prefs, 'order:status-update')).toBe(false);
      expect(shouldSendEmailForPreferences(prefs, 'user:welcome')).toBe(true);
      expect(shouldSendEmailForPreferences(prefs, 'user:profile-updated')).toBe(false);
    });
  });

  describe('shouldSendSmsForPreferences', () => {
    it('should return false when preferences are undefined (SMS is opt-in)', () => {
      expect(shouldSendSmsForPreferences(undefined, 'order:confirmation')).toBe(false);
    });

    it('should return false when SMS is disabled (default)', () => {
      const prefs = makePreferences();
      expect(shouldSendSmsForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should return true when SMS is enabled and category is enabled', () => {
      const prefs = makePreferences({
        sms: {
          enabled: true,
          phoneNumber: '+1234567890',
          categories: { ...DEFAULT_SMS_PREFERENCES.categories },
        },
      });
      expect(shouldSendSmsForPreferences(prefs, 'order:confirmation')).toBe(true);
    });

    it('should return false when SMS is enabled but category is disabled', () => {
      const prefs = makePreferences({
        sms: {
          enabled: true,
          phoneNumber: '+1234567890',
          categories: {
            ...DEFAULT_SMS_PREFERENCES.categories,
            orderConfirmations: false,
          },
        },
      });
      expect(shouldSendSmsForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should check each notification type against its category', () => {
      const prefs = makePreferences({
        sms: {
          enabled: true,
          phoneNumber: '+1234567890',
          categories: {
            orderConfirmations: true,
            orderStatusUpdates: false,
            welcomeMessages: true,
            profileUpdates: false,
          },
        },
      });

      expect(shouldSendSmsForPreferences(prefs, 'order:confirmation')).toBe(true);
      expect(shouldSendSmsForPreferences(prefs, 'order:status-update')).toBe(false);
      expect(shouldSendSmsForPreferences(prefs, 'user:welcome')).toBe(true);
      expect(shouldSendSmsForPreferences(prefs, 'user:profile-updated')).toBe(false);
    });
  });

  describe('shouldSendWebhookForPreferences', () => {
    it('should return false when preferences are undefined (webhook is opt-in)', () => {
      expect(shouldSendWebhookForPreferences(undefined, 'order:confirmation')).toBe(false);
    });

    it('should return false when webhook is disabled (default)', () => {
      const prefs = makePreferences();
      expect(shouldSendWebhookForPreferences(prefs, 'order:confirmation')).toBe(false);
    });

    it('should return true when webhook is enabled and category is enabled', () => {
      const prefs = makePreferences({
        webhook: {
          enabled: true,
          url: 'https://example.com/webhook',
          categories: { ...DEFAULT_WEBHOOK_PREFERENCES.categories },
        },
      });
      expect(shouldSendWebhookForPreferences(prefs, 'order:confirmation')).toBe(true);
    });

    it('should return false when webhook is enabled but category is disabled', () => {
      const prefs = makePreferences({
        webhook: {
          enabled: true,
          url: 'https://example.com/webhook',
          categories: {
            ...DEFAULT_WEBHOOK_PREFERENCES.categories,
            orderStatusUpdates: false,
          },
        },
      });
      expect(shouldSendWebhookForPreferences(prefs, 'order:status-update')).toBe(false);
    });
  });

  describe('shouldSendForChannel', () => {
    it('should dispatch to email check', () => {
      const prefs = makePreferences();
      expect(shouldSendForChannel(prefs, 'order:confirmation', 'email')).toBe(true);
    });

    it('should dispatch to sms check', () => {
      const prefs = makePreferences();
      expect(shouldSendForChannel(prefs, 'order:confirmation', 'sms')).toBe(false);
    });

    it('should dispatch to webhook check', () => {
      const prefs = makePreferences();
      expect(shouldSendForChannel(prefs, 'order:confirmation', 'webhook')).toBe(false);
    });

    it('should always allow in-app notifications', () => {
      const prefs = makePreferences();
      expect(shouldSendForChannel(prefs, 'order:confirmation', 'in-app')).toBe(true);
    });

    it('should handle undefined preferences per channel defaults', () => {
      // Email defaults to allowed, SMS and webhook default to blocked
      expect(shouldSendForChannel(undefined, 'order:confirmation', 'email')).toBe(true);
      expect(shouldSendForChannel(undefined, 'order:confirmation', 'sms')).toBe(false);
      expect(shouldSendForChannel(undefined, 'order:confirmation', 'webhook')).toBe(false);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { Database } from '../../src/utils/database.js';
import { UserRepository } from '../../src/repositories/user.repository.js';
import { PreferencesRepository } from '../../src/repositories/preferences.repository.js';
import {
  PreferencesService,
  resetPreferencesIdCounter,
} from '../../src/services/preferences.service.js';
import type { User } from '../../src/models/user.js';

function makeUser(overrides?: Partial<User>): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

describe('PreferencesService', () => {
  let db: Database;
  let userRepo: UserRepository;
  let prefsRepo: PreferencesRepository;
  let service: PreferencesService;

  beforeEach(() => {
    db = new Database();
    userRepo = new UserRepository(db);
    prefsRepo = new PreferencesRepository(db);
    service = new PreferencesService(prefsRepo, userRepo);
    resetPreferencesIdCounter();
  });

  describe('getPreferences', () => {
    it('should return undefined when no preferences exist', () => {
      expect(service.getPreferences('user-0001')).toBeUndefined();
    });

    it('should return preferences after they are created', () => {
      const user = makeUser();
      userRepo.save(user);
      service.getOrCreatePreferences('user-0001');

      const prefs = service.getPreferences('user-0001');
      expect(prefs).toBeDefined();
      expect(prefs!.userId).toBe('user-0001');
    });
  });

  describe('getOrCreatePreferences', () => {
    it('should create default preferences for a new user', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.id).toBe('pref-0001');
      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(true);
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.orderConfirmations).toBe(true);
      expect(prefs.email.categories.orderStatusUpdates).toBe(true);
      expect(prefs.email.categories.welcomeMessages).toBe(true);
      expect(prefs.email.categories.profileUpdates).toBe(true);
    });

    it('should create default SMS preferences (disabled)', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.sms.enabled).toBe(false);
      expect(prefs.sms.categories.orderConfirmations).toBe(true);
      expect(prefs.sms.categories.orderStatusUpdates).toBe(true);
    });

    it('should create default webhook preferences (disabled)', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.getOrCreatePreferences('user-0001');

      expect(prefs.webhook.enabled).toBe(false);
      expect(prefs.webhook.categories.orderConfirmations).toBe(true);
    });

    it('should return existing preferences without creating duplicates', () => {
      const user = makeUser();
      userRepo.save(user);

      const first = service.getOrCreatePreferences('user-0001');
      const second = service.getOrCreatePreferences('user-0001');

      expect(first.id).toBe(second.id);
      expect(prefsRepo.count()).toBe(1);
    });

    it('should throw if user does not exist', () => {
      expect(() => service.getOrCreatePreferences('nonexistent')).toThrow(
        'User not found: nonexistent',
      );
    });

    it('should generate sequential IDs', () => {
      const user1 = makeUser({ id: 'user-0001' });
      const user2 = makeUser({ id: 'user-0002', email: 'bob@example.com' });
      userRepo.save(user1);
      userRepo.save(user2);

      const prefs1 = service.getOrCreatePreferences('user-0001');
      const prefs2 = service.getOrCreatePreferences('user-0002');

      expect(prefs1.id).toBe('pref-0001');
      expect(prefs2.id).toBe('pref-0002');
    });
  });

  describe('updateEmailPreferences', () => {
    it('should disable email notifications', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateEmailPreferences('user-0001', {
        enabled: false,
      });

      expect(prefs.email.enabled).toBe(false);
      // Other settings preserved
      expect(prefs.email.frequency).toBe('immediate');
      expect(prefs.email.categories.orderConfirmations).toBe(true);
    });

    it('should update frequency', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateEmailPreferences('user-0001', {
        frequency: 'daily-digest',
      });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.email.enabled).toBe(true);
    });

    it('should update individual categories', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateEmailPreferences('user-0001', {
        categories: {
          orderStatusUpdates: false,
          profileUpdates: false,
        },
      });

      expect(prefs.email.categories.orderConfirmations).toBe(true);
      expect(prefs.email.categories.orderStatusUpdates).toBe(false);
      expect(prefs.email.categories.welcomeMessages).toBe(true);
      expect(prefs.email.categories.profileUpdates).toBe(false);
    });

    it('should update multiple fields at once', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateEmailPreferences('user-0001', {
        frequency: 'weekly-digest',
        categories: { welcomeMessages: false },
      });

      expect(prefs.email.frequency).toBe('weekly-digest');
      expect(prefs.email.categories.welcomeMessages).toBe(false);
      expect(prefs.email.categories.orderConfirmations).toBe(true);
    });

    it('should create preferences if none exist', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateEmailPreferences('user-0001', {
        enabled: false,
      });

      expect(prefs.userId).toBe('user-0001');
      expect(prefs.email.enabled).toBe(false);
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updateEmailPreferences('nonexistent', { enabled: false }),
      ).toThrow('User not found: nonexistent');
    });

    it('should update the updatedAt timestamp', () => {
      const user = makeUser();
      userRepo.save(user);

      const original = service.getOrCreatePreferences('user-0001');
      const originalUpdatedAt = original.updatedAt;

      const updated = service.updateEmailPreferences('user-0001', {
        enabled: false,
      });

      expect(updated.updatedAt.getTime()).toBeGreaterThanOrEqual(
        originalUpdatedAt.getTime(),
      );
    });

    it('should not affect SMS or webhook preferences', () => {
      const user = makeUser();
      userRepo.save(user);

      // Enable SMS first
      service.updateSmsPreferences('user-0001', { enabled: true, phoneNumber: '+1234567890' });

      // Update email
      const prefs = service.updateEmailPreferences('user-0001', { enabled: false });

      expect(prefs.email.enabled).toBe(false);
      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.phoneNumber).toBe('+1234567890');
    });
  });

  describe('updateSmsPreferences', () => {
    it('should enable SMS notifications', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateSmsPreferences('user-0001', {
        enabled: true,
        phoneNumber: '+1234567890',
      });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.phoneNumber).toBe('+1234567890');
    });

    it('should update SMS categories', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateSmsPreferences('user-0001', {
        enabled: true,
        categories: { orderConfirmations: false },
      });

      expect(prefs.sms.enabled).toBe(true);
      expect(prefs.sms.categories.orderConfirmations).toBe(false);
      expect(prefs.sms.categories.orderStatusUpdates).toBe(true);
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updateSmsPreferences('nonexistent', { enabled: true }),
      ).toThrow('User not found: nonexistent');
    });

    it('should not affect email preferences', () => {
      const user = makeUser();
      userRepo.save(user);

      service.updateEmailPreferences('user-0001', { frequency: 'daily-digest' });
      const prefs = service.updateSmsPreferences('user-0001', { enabled: true });

      expect(prefs.email.frequency).toBe('daily-digest');
      expect(prefs.sms.enabled).toBe(true);
    });
  });

  describe('updateWebhookPreferences', () => {
    it('should enable webhook notifications', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateWebhookPreferences('user-0001', {
        enabled: true,
        url: 'https://example.com/webhook',
      });

      expect(prefs.webhook.enabled).toBe(true);
      expect(prefs.webhook.url).toBe('https://example.com/webhook');
    });

    it('should update webhook categories', () => {
      const user = makeUser();
      userRepo.save(user);

      const prefs = service.updateWebhookPreferences('user-0001', {
        enabled: true,
        categories: { welcomeMessages: false, profileUpdates: false },
      });

      expect(prefs.webhook.categories.orderConfirmations).toBe(true);
      expect(prefs.webhook.categories.welcomeMessages).toBe(false);
      expect(prefs.webhook.categories.profileUpdates).toBe(false);
    });

    it('should throw if user does not exist', () => {
      expect(() =>
        service.updateWebhookPreferences('nonexistent', { enabled: true }),
      ).toThrow('User not found: nonexistent');
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when no preferences exist (default behavior)', () => {
      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return true when email is enabled and category is enabled', () => {
      const user = makeUser();
      userRepo.save(user);
      service.getOrCreatePreferences('user-0001');

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'user:profile-updated')).toBe(true);
    });

    it('should return false when email is globally disabled', () => {
      const user = makeUser();
      userRepo.save(user);
      service.updateEmailPreferences('user-0001', { enabled: false });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'user:welcome')).toBe(false);
      expect(service.shouldSendEmail('user-0001', 'user:profile-updated')).toBe(false);
    });

    it('should return false for a disabled category', () => {
      const user = makeUser();
      userRepo.save(user);
      service.updateEmailPreferences('user-0001', {
        categories: { orderStatusUpdates: false },
      });

      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(true);
      expect(service.shouldSendEmail('user-0001', 'order:status-update')).toBe(false);
    });

    it('should return false when master switch is off even if category is on', () => {
      const user = makeUser();
      userRepo.save(user);
      service.updateEmailPreferences('user-0001', { enabled: false });

      // All categories are still enabled by default, but master switch is off
      expect(service.shouldSendEmail('user-0001', 'order:confirmation')).toBe(false);
    });
  });

  describe('shouldSendSms', () => {
    it('should return false when no preferences exist (SMS is opt-in)', () => {
      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(false);
    });

    it('should return false with default preferences (SMS disabled by default)', () => {
      const user = makeUser();
      userRepo.save(user);
      service.getOrCreatePreferences('user-0001');

      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(false);
    });

    it('should return true when SMS is explicitly enabled', () => {
      const user = makeUser();
      userRepo.save(user);
      service.updateSmsPreferences('user-0001', { enabled: true, phoneNumber: '+1234567890' });

      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(true);
    });

    it('should return false for disabled SMS category', () => {
      const user = makeUser();
      userRepo.save(user);
      service.updateSmsPreferences('user-0001', {
        enabled: true,
        categories: { orderConfirmations: false },
      });

      expect(service.shouldSendSms('user-0001', 'order:confirmation')).toBe(false);
      expect(service.shouldSendSms('user-0001', 'order:status-update')).toBe(true);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return false when no preferences exist (webhook is opt-in)', () => {
      expect(service.shouldSendWebhook('user-0001', 'order:confirmation')).toBe(false);
    });

    it('should return true when webhook is explicitly enabled', () => {
      const user = makeUser();
      userRepo.save(user);
      service.updateWebhookPreferences('user-0001', {
        enabled: true,
        url: 'https://example.com/hook',
      });

      expect(service.shouldSendWebhook('user-0001', 'order:confirmation')).toBe(true);
    });
  });

  describe('shouldSendOnChannel', () => {
    it('should dispatch to the correct channel check', () => {
      const user = makeUser();
      userRepo.save(user);
      service.getOrCreatePreferences('user-0001');

      // Email enabled by default
      expect(service.shouldSendOnChannel('user-0001', 'order:confirmation', 'email')).toBe(true);
      // SMS disabled by default
      expect(service.shouldSendOnChannel('user-0001', 'order:confirmation', 'sms')).toBe(false);
      // Webhook disabled by default
      expect(service.shouldSendOnChannel('user-0001', 'order:confirmation', 'webhook')).toBe(false);
    });
  });
});

